(122, 1, 'Botble\\ACL\\Models\\User', 'page', '{\"name\":\"Boton Blue Dining & Lounge\",\"model\":\"Botble\\\\Page\\\\Models\\\\Page\",\"slug\":\"dining\",\"slug_id\":\"82\",\"is_slug_editable\":\"1\",\"description\":\"Enjoy the finest dining in town\",\"content\":\"<shortcode>[services data-vb-id=\\\"shortcode_1773398041_0\\\" id=\\\"shortcode_1773397233_0\\\" title=\\\"Asian Restaurant\\\" subtitle=\\\"Opening hour: daily 10:00 - 22:00\\\" description=\\\"Located on the 8th floor of the Boton Blue Hotel &amp; Spa with a panoramic view of the infinity pool and the vast ocean, Asian restaurant gives you exciting moments to enjoy authentic Asian cuisine by friends and relatives.\\\" left_image=\\\"dinning\\/1.png\\\" button_label=\\\"View Details\\\" button_url=\\\"\\/asian-restaurant\\\"][\\/services]<\\/shortcode><shortcode>[feature-area data-vb-id=\\\"shortcode_1773398041_1\\\" id=\\\"shortcode_1773397233_1\\\" title=\\\"Blue Ocean Bar\\\" subtitle=\\\"Daily 8:00 AM \\u2013 9:00 PM\\\" description=\\\"Off the main pool, it is al fresco environment encourages lingering over classic summertime tastes in the Nha Trang sunshine. Order up tropical drinks and sip on refreshing specialty cocktails while you enjoy great conversation and beach-style tunes.\\\" image=\\\"dinning\\/blue-ocean-bar\\/3.png\\\" button_primary_label=\\\"View Details\\\" button_primary_url=\\\"\\/blue-ocean-bar\\\"][\\/feature-area]<\\/shortcode><shortcode>[feature-area data-vb-id=\\\"shortcode_1773398041_2\\\" id=\\\"shortcode_1773397233_2\\\" title=\\\"Sunflower Restaurant\\\" subtitle=\\\"Daily 6:30 AM - 10:00 AM\\\" description=\\\"Directly overlooking the beautiful ocean, Sunflower Restaurant is the perfect place to start the day with a scrumptious breakfast. A daily breakfast buffet serves the Western and Asian cuisine that suite every taste. The restaurant also serves an innovative a la carte menu for lunch and dinner, buffet for the...\\\" image=\\\"dinning\\/sunflower-restaurant\\/1.png\\\" button_primary_label=\\\"View Details\\\" button_primary_url=\\\"\\/sunflower-restaurant\\\"][\\/feature-area]<\\/shortcode><shortcode>[feature-area data-vb-id=\\\"shortcode_1773398041_3\\\" id=\\\"shortcode_1773397233_3\\\" title=\\\"Guangdong Restaurant\\\" subtitle=\\\"Monday - Sunday: 16:30 - 22:00\\\" description=\\\"Enjoy fine Chinese cuisine at Guangdong Restaurant while soaking in the breathtaking view of the bay. With its interior adorned with black-red background d\\u00e9cor and traditional lanterns, Guangdong Restaurant creates an immersive atmosphere complementing our elegant cuisine.\\\" image=\\\"dinning\\/guangdong-restaurant\\/959x642.png\\\" button_primary_label=\\\"View Details\\\" button_primary_url=\\\"guangdong-restaurant\\\"][\\/feature-area]<\\/shortcode>\",\"gallery\":null,\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"apply\",\"status\":\"published\",\"template\":\"full-width\",\"breadcrumb\":\"1\",\"breadcrumb_background\":\"dinning\\/959-x-285-1.png\",\"image\":null}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36', '171.243.62.68', 1, 'Botble\\ACL\\Models\\User', 14, 'Boton Blue Dining & Lounge', 'primary', '2026-03-13 22:22:55', '2026-03-13 22:22:55'),
