INSERT INTO `audit_histories` (`id`, `user_id`, `user_type`, `module`, `request`, `action`, `user_agent`, `ip_address`, `actor_id`, `actor_type`, `reference_id`, `reference_name`, `type`, `created_at`, `updated_at`) VALUES
(193, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"BOTON BLUE HOTEL & SPA YEAR-END PARTY\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"boton-blue-hotel-spa-year-end-party\",\"slug_id\":\"11\",\"is_slug_editable\":\"1\",\"description\":\"On the evening of February 4, the entire Boton Blue Hotel & Spa family came together for a warm and memorable year-end celebration held at the Lotus Lobby on the 3rd floor of the hotel, with the presence of the Management Board and all team members.\",\"is_featured\":\"1\",\"content\":\"<p>The event took place in a lively and connected atmosphere, featuring vibrant artistic performances, engaging interactive games, and many meaningful gifts\\u2014serving as a heartfelt token of appreciation for the team\\u2019s unwavering dedication and efforts throughout the past year.<\\/p><p>During the celebration, the Hotel Management shared sincere reflections, recognizing the contribution of each individual while inspiring and encouraging the entire team to continue upholding a spirit of commitment, continuously enhancing service quality, and delivering the most fulfilling experiences to our guests.<\\/p><p>&nbsp;<\\/p><p>On the occasion of the Lunar New Year of B\\u00ednh Ng\\u1ecd, Boton Blue Hotel &amp; Spa extends its best wishes to the Management Board and all staff members for good health, lasting happiness, and continued success as we together reach new milestones on our journey ahead.<\\/p>\",\"gallery\":\"[{\\\"img\\\":\\\"news\\/spa-year-end-party\\/z7503628521898-8a8c6d62260735120ea8184e519ad432.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/spa-year-end-party\\/z7503628521889-423669f7fe314de18a14d43e9a760d61.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/spa-year-end-party\\/z7503628521883-2ee85c03b8ed83c8ba537cebed2c64f6.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/spa-year-end-party\\/z7503628510147-21abf57410a36f4fa8b750b115ecd391.jpeg\\\",\\\"description\\\"