(206, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"CHRISTMAS HARMONY NIGHT 2025\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"christmas-harmony-night-2025\",\"slug_id\":\"12\",\"is_slug_editable\":\"1\",\"description\":\"Let us look back on the unforgettable moments of CHRISTMAS HARMONY NIGHT 2025 at Boton Blue Hotel & Spa \\u2014 an evening where sparkling lights, elegant melodies, and a warm festive atmosphere came together to create a truly enchanting Christmas celebration.\",\"is_featured\":\"1\",\"content\":\"<p>&nbsp;Let us look back on the unforgettable moments of CHRISTMAS HARMONY NIGHT 2025 at Boton Blue Hotel &amp; Spa \\u2014 an evening where sparkling lights, elegant melodies, and a warm festive atmosphere came together to create a truly enchanting Christmas celebration.<\\/p><p>From joyful smiles and heartwarming moments shared around the festive table to the melodies echoing through our elegant venue, every detail contributed to a night filled with beautiful memories and lasting impressions.<\\/p>\",\"gallery\":\"[{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/img-4714.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/img-4665.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/605635909-1510324114433022-4626118969605943890-n.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/605632495-1510324281099672-6672050166092208469-n.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/603921758-1510324137766353-1838582787556528216-n.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/603902553-1510325271099573-6993433745241344189-n.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/christmas-harmony-night-2025\\/603837605-1510324211099679-3238761874027877522-n.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":