(207, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"OFFICIAL ANNOUNCEMENT FROM BOTON BLUE HOTEL & SPA\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"official-announcement-from-boton-blue-hotel-spa\",\"slug_id\":\"13\",\"is_slug_editable\":\"1\",\"description\":\"Driven by our aspiration to elevate guest experiences and proudly represent a Vietnamese luxury hotel brand on the global stage, Boton Blue Hotel & Spa is delighted to announce:\",\"is_featured\":\"0\",\"content\":\"<pre><code class=\\\"language-plaintext\\\">\\ud83c\\udf10 OFFICIAL ANNOUNCEMENT FROM BOTON BLUE HOTEL &amp; SPA \\ud83c\\udf10\\r\\nDear Valued Guests and Partners,\\r\\n\\r\\nDriven by our aspiration to elevate guest experiences and proudly represent a Vietnamese luxury hotel brand on the global stage, Boton Blue Hotel &amp; Spa is delighted to announce:\\r\\n\\r\\n\\u2728 Our official website has been updated to a new domain:\\r\\n\\ud83d\\udc49 https:\\/\\/botonbluehotels.com\\r\\n\\r\\nThis transition marks an important milestone in our journey to expand the Vietnamese-owned Boton Blue brand, aiming to become an internationally recognized hotel group while staying true to our Vietnamese hospitality spirit and national pride in every service we deliver.\\r\\n\\r\\n\\ud83d\\udce9 All information and services remain secure and unchanged, ensuring the highest standards of quality and reliability.\\r\\nWe kindly invite our valued guests and partners to update the new website and continue accompanying Boton Blue Hotel &amp; Spa in celebrating Vietnamese excellence in world-class hospitality by the stunning shores of Nha Trang.\\r\\n\\r\\nWarm regards,\\r\\nBOTON BLUE HOTEL &amp; SPA<\\/code><\\/pre>\",\"gallery\":\"[{\\\"img\\\":\\\"news\\/official-announcement\\/z7143800919525-2687d38dcd5d9603a273490d79d7b01e.jpeg\\\",\\\"description\\\":\\\"\\\"}]\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"save\",\"status\":\"published\",\"image\":\"news\\/official-announcement\\/z7143800919525-2687d38dcd5d9603a273490d79d7b01e.jpeg\",\"tag\":null}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36', '171.243.63.154', 1, 'Botble\\ACL\\Models\\User', 3, 'OFFICIAL ANNOUNCEMENT FROM BOTON BLUE HOTEL & SPA', 'primary', '2026-03-16 21:13:02', '2026-03-16 21:13:02'),
