(211, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"THE GRAND TUNA BUFFET PARTY\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"the-grand-tuna-buffet-party\",\"slug_id\":\"14\",\"is_slug_editable\":\"1\",\"description\":\"On the evening of September 1st, the Oceanic Tuna Buffet Party took place in a luxurious and cozy setting at the Asian Restaurant, 8th floor of Boton Blue Hotel & Spa.\",\"is_featured\":\"0\",\"content\":\"<p>LET\\u2019S RECAP THE UNFORGETTABLE MOMENTS FROM THE OCEANIC TUNA BUFFET PARTY<\\/p><p>On the evening of September 1st, the Oceanic Tuna Buffet Party took place in a luxurious and cozy setting at the Asian Restaurant, 8th floor of Boton Blue Hotel &amp; Spa.<\\/p><p>\\u2728 Highlights of the Night:<\\/p><p>\\ud83d\\udc1f Witnessed the spectacular performance and preparation of a 50kg giant oceanic tuna.<\\/p><p>\\ud83c\\udf7d\\ufe0f Indulged in a special menu featuring rich, fresh tuna sashimi, flavorful seared tuna, tangy fermented tuna hotpot, and hearty tuna dishes perfect for sharing.<\\/p><p>\\ud83c\\udfb5 Enjoyed a warm and intimate atmosphere with acoustic live music themed \\u201cNational Pride\\u201d.<\\/p><p>Boton Blue would like to extend our heartfelt thanks to all our valued guests for joining us and making this event truly memorable.<\\/p><p>\\ud83d\\udcf8 Let\\u2019s take a look back at these vibrant snapshots and cherish the unforgettable memories from this special night!<\\/p>\",\"gallery\":\"[{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4367.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4381.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4366.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4364.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4360.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4359.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4356.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4351.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4350.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4338.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4336.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4331.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4329.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4323.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4319.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4313.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/the-grand-tuna-buffet-party\\/img-4311.jpeg\\\",\\\"description\\\":\\\"\\\"}]\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"submitter\":\"save\",\"status\":\"published\",\"image\":\"news\\/the-grand-tuna-buffet-party\\/img-4329.jpeg\",\"tag\":null}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36', '171.243.63.154', 1, 'Botble\\ACL\\Models\\User', 4, 'THE GRAND TUNA BUFFET PARTY', 'primary', '2026-03-16 21:24:17', '2026-03-16 21:24:17'),
