(306, 1, 'Botble\\ACL\\Models\\User', 'post', '{\"name\":\"20th Reunion of Class 43 \\u2013 Nha Trang University at Boton Blue Hotel & Spa\",\"model\":\"Botble\\\\Blog\\\\Models\\\\Post\",\"slug\":\"20th-reunion-of-class-43-nha-trang-university-at-boton-blue-hotel-spa\",\"slug_id\":\"15\",\"is_slug_editable\":\"1\",\"description\":\"This past Saturday, Boton Blue Hotel & Spa had the great honor of hosting the 20-year class reunion for Class 43 \\u2013 Faculty of Aquaculture and Environment, Nha Trang University (Cohort 2001\\u20132005) at the Lotus Ballroom \\u2013 3rd Floor.\",\"is_featured\":\"1\",\"content\":\"<p>\\ud83c\\udf93 20th Reunion of Class 43 \\u2013 Nha Trang University at Boton Blue Hotel &amp; Spa<\\/p><p>\\u2728 This past Saturday, Boton Blue Hotel &amp; Spa had the great honor of hosting the 20-year class reunion for Class 43 \\u2013 Faculty of Aquaculture and Environment, Nha Trang University (Cohort 2001\\u20132005) at the Lotus Ballroom \\u2013 3rd Floor.<\\/p><p>Warm embraces, radiant smiles, and stories that felt like they just happened yesterday \\u2014 all brought back the vibrant and innocent days of youth under the beloved university roof.<\\/p><p>\\u2728 We sincerely thank the alumni of Class 43 \\u2013 Nha Trang University for trusting and choosing Boton Blue as the venue to reunite after 20 years. It was a true pleasure to accompany you in such a meaningful milestone.<\\/p><p>We wish you all continued health, happiness, and a lifelong bond of friendship as you move forward on your journeys.<\\/p><p>\\ud83d\\udccd Planning a class reunion, school anniversary, or group celebration? Feel free to inbox our fanpage or contact 0889 499 898 for venue consultation tailored to your needs!<\\/p>\",\"gallery\":\"[{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/img-4203.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/img-4196.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/img-4187.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/img-4185.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/img-4180.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/gen-h-z6871141313233-c9c27e25c80ef6c2735e310d4d13e9c9.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/gen-h-z6871141288152-58005faf9549fb263af06d6e2d2bbd16.jpeg\\\",\\\"description\\\":\\\"\\\"},{\\\"img\\\":\\\"news\\/20th-reunion-of-class-43\\/gen-h-z6871141271576-b04676a18e5beb64a3a142e2b6f82fa2.jpeg\\\",\\\"description\\\":\\\"\\\"}]\",\"seo_meta\":{\"seo_title\":null,\"seo_description\":null,\"index\":\"index\"},\"seo_meta_image\":null,\"status\":\"published\",\"image\":\"news\\/20th-reunion-of-class-43\\/gen-h-z6871141271576-b04676a18e5beb64a3a142e2b6f82fa2.jpeg\",\"tag\":null,\"submitter\":\"save\"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36', '171.243.63.154', 1, 'Botble\\ACL\\Models\\User', 5, '20th Reunion of Class 43 – Nha Trang University at Boton Blue Hotel & Spa', 'primary', '2026-03-16 23:42:25', '2026-03-16 23:42:25'),
