-- Đang đổ dữ liệu cho bảng `galleries`
--

INSERT INTO `galleries` (`id`, `name`, `description`, `is_featured`, `order`, `image`, `user_id`, `status`, `created_at`, `updated_at`) VALUES
(1, 'BOTON BLUE HOTEL &amp; SPA YEAR-END PARTY', '<p><span style=\"background-color:rgb(255,255,255);color:rgb(51,51,51);\"><span style=\"font-family:\'Open Sans\', sans-serif;font-size:14px;font-style:normal;font-weight:500;text-align:center;word-spacing:0px;\">On the evening of February 4, the entire Boton Blue Hotel &amp; Spa family came together for a warm and memorable year-end celebration held at the Lotus Lobby on the 3rd floor of the hotel, with the presence of the Management Board and all team members.</span></span></p>', 1, 0, 'news/spa-year-end-party/z7503628521909-a0f44d7ad70f76746c6e59f50b7eaa36.jpeg', 1, 'published', '2025-06-10 10:38:16', '2026-03-16 23:44:52'),
(2, 'CHRISTMAS HARMONY NIGHT 2025', '<p><span style=\"background-color:rgb(255,255,255);color:rgb(51,51,51);\"><span style=\"font-family:\'Open Sans\', sans-serif;font-size:14px;font-style:normal;font-weight:500;text-align:center;word-spacing:0px;\">Let us look back on the unforgettable moments of CHRISTMAS HARMONY NIGHT 2025 at Boton Blue Hotel &amp; Spa — an evening where sparkling lights, elegant melodies, and a warm festive atmosphere came together to create a truly enchanting Christmas celebration.</span></span></p>', 1, 0, 'news/christmas-harmony-night-2025/603902553-1510325271099573-6993433745241344189-n.jpeg', 1, 'published', '2025-06-10 10:38:16', '2026-03-16 23:45:34'),
(3, 'THE GRAND TUNA BUFFET PARTY', '<p><span style=\"background-color:rgb(255,255,255);color:rgb(51,51,51);\"><span style=\"font-family:\'Open Sans\', sans-serif;font-size:14px;font-style:normal;font-weight:500;text-align:center;word-spacing:0px;\">On the evening of September 1st, the Oceanic Tuna Buffet Party took place in a luxurious and cozy setting at the Asian Restaurant, 8th floor of Boton Blue Hotel &amp; Spa.</span> </span></p>', 1, 0, 'news/the-grand-tuna-buffet-party/img-4329.jpeg', 1, 'published', '2025-06-10 10:38:16', '2026-03-16 23:50:30'),
(4, '20th Reunion of Class 43 – Nha Trang University at Boton Blue Hotel &amp; Spa', '<p><span style=\"background-color:rgb(255,255,255);color:rgb(51,51,51);\"><span style=\"font-family:\'Open Sans\', sans-serif;font-size:14px;font-style:normal;font-weight:500;text-align:center;word-spacing:0px;\">This past Saturday, Boton Blue Hotel &amp; Spa had the great honor of hosting the 20-year class reunion for Class 43 – Faculty of Aquaculture and Environment, Nha Trang University (Cohort 2001–2005) at the Lotus Ballroom – 3rd Floor.</span></span></p>', 1, 0, 'news/20th-reunion-of-class-43/gen-h-z6871141271576-b04676a18e5beb64a3a142e2b6f82fa2.jpeg', 1, 'published', '2025-06-10 10:38:16', '2026-03-16 23:51:04');

