-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `ht_places_translations`
--

DROP TABLE IF EXISTS `ht_places_translations`;
CREATE TABLE `ht_places_translations` (
  `lang_code` varchar(191) NOT NULL,
  `ht_places_id` bigint(20) UNSIGNED NOT NULL,
  `name` varchar(191) DEFAULT NULL,
  `distance` text DEFAULT NULL,
  `description` text DEFAULT NULL,
  `content` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Cấu trúc bảng cho bảng `ht_rooms`
--

DROP TABLE IF EXISTS `ht_rooms`;
CREATE TABLE `ht_rooms` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `name` varchar(120) NOT NULL,
  `description` text DEFAULT NULL,
  `content` longtext DEFAULT NULL,
  `is_featured` tinyint(3) UNSIGNED NOT NULL DEFAULT 0,
  `images` text DEFAULT NULL,
  `price` decimal(15,0) UNSIGNED DEFAULT NULL,
  `currency_id` bigint(20) UNSIGNED DEFAULT NULL,
  `number_of_rooms` int(10) UNSIGNED DEFAULT 0,
  `number_of_beds` int(10) UNSIGNED DEFAULT 0,
  `size` int(10) UNSIGNED DEFAULT 0,
  `max_adults` int(11) DEFAULT 0,
  `max_children` int(11) DEFAULT 0,
  `room_category_id` bigint(20) UNSIGNED DEFAULT NULL,
  `tax_id` bigint(20) UNSIGNED DEFAULT NULL,
  `status` varchar(60) NOT NULL DEFAULT 'published',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `order` int(10) UNSIGNED NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Đang đổ dữ liệu cho bảng `ht_rooms`
--

INSERT INTO `ht_rooms` (`id`, `name`, `description`, `content`, `is_featured`, `images`, `price`, `currency_id`, `number_of_rooms`, `number_of_beds`, `size`, `max_adults`, `max_children`, `room_category_id`, `tax_id`, `status`, `created_at`, `updated_at`, `order`) VALUES
(1, 'Superior Twin Room With Mountain View', 'An ideal choice for those who appreciate tranquility and scenic views. With a spacious private balcony overlooking the majestic Co Tien Mountain, the Superior Twin Room With Mountain View offers a serene ambiance where guests can unwind and immerse themselves in the peaceful beauty of Nha Trang.', '<p>Superior Twin Room With Mountain View&nbsp;– A peaceful retreat embraced by nature</p><p>An ideal choice for those who appreciate tranquility and scenic views. With a spacious private balcony overlooking the majestic Co Tien Mountain, the Superior Mountain room offers a serene ambiance where guests can unwind and immerse themselves in the peaceful beauty of Nha Trang.</p><p>Highlights:</p><p>- 38m² with modern design, warm tones, and luxurious walnut wood furnishings</p><p>- Two single beds with 5-star standard spring mattresses</p><p>- Spacious private balcony facing the mountain, catching natural sunlight and breeze</p><p>- Low-E soundproof glass, UV-resistant (alpha, beta, gamma rays), for optimal skin and health protection</p><p>- Bathroom with premium imported sanitary ware by Grohe – a leading European brand</p><p>- One of the safest fire protection systems in Nha Trang (fireproof elevators, doors, curtains, carpets...)</p><p>- Free 2 bottles of water daily, fully stocked minibar, high-speed Wifi</p><p>- Complimentary access to infinity pool and gym</p>', 0, '{\"1\":\"img-superiorm\\/2.png\",\"2\":\"img-superiorm\\/3.png\",\"3\":\"img-superiorm\\/4.png\",\"4\":\"img-superiorm\\/5.png\",\"5\":\"img-superiorm\\/6.png\",\"6\":\"img-superiorm\\/7.png\",\"7\":\"img-superiorm\\/8.png\",\"8\":\"img-superiorm\\/1.png\"}', '0', NULL, 1, 2, 38, 1, 0, 5, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:05:13', 0),
(2, 'Superior Double Room With Partial Ocean View', 'Superior Double Room With Partial Ocean View offers a private balcony with views of Co Tien Mountain and Nha Trang Bay. Enjoy the romantic sea view and refreshing breeze each day. Ideal for morning coffee on the balcony or watching the sunset after a day of exploration.', '<p>Superior Double Room With Partial Ocean View&nbsp;– Start your day with sparkling sunshine over the sea</p><p>Superior Double Room With Partial Ocean View offers a private balcony with views of Co Tien Mountain and Nha Trang Bay. Enjoy the romantic sea view and refreshing breeze each day. Ideal for morning coffee on the balcony or watching the sunset after a day of exploration.</p><p>Highlights:</p><p>- 28m² with modern design, warm tones, and luxurious walnut wood furnishings</p><p>- Private balcony facing the sea and mountains, welcoming sunlight and ocean breeze</p><p>- Cozy double bed with high-quality spring mattress for deep sleep</p><p>- Low-E soundproof glass, UV-resistant (alpha, beta, gamma rays) for optimal skin and health protection</p><p>- Premium imported sanitary ware by Grohe – a leading European brand</p><p>- One of the safest fire protection systems in Nha Trang (fireproof elevator, door, curtain, carpet…)</p><p>- Free 2 bottles of water daily, fully stocked minibar, high-speed Wifi</p><p>- Complimentary use of infinity pool &amp; gym</p>', 1, '{\"1\":\"img-superiors\\/1.png\",\"2\":\"img-superiors\\/2.png\",\"3\":\"img-superiors\\/3.png\",\"4\":\"img-superiors\\/4.png\",\"5\":\"img-superiors\\/5.png\",\"6\":\"img-superiors\\/6.png\"}', '0', NULL, 7, 2, 28, 2, 2, 5, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:04:58', 0),
(3, 'Deluxe Double Room With Partial Sea View', 'With a private balcony facing the sea and city, the Deluxe Room offers an ideal space where natural beauty meets urban rhythm. Relax on a cozy sofa bed, listen to the gentle waves, and enjoy a truly relaxing stay.', '<p>Deluxe Double Room With Partial Sea View&nbsp;– A refined and comfortable retreat</p><p>With a private balcony facing the sea and city, the Deluxe Room offers an ideal space where natural beauty meets urban rhythm. Relax on a cozy sofa bed, listen to the gentle waves, and enjoy a truly relaxing stay.</p><p>Highlights:</p><p>- 34–39m² with modern design, warm tones, and luxurious walnut wood furnishings</p><p>- Private balcony with sea and city view</p><p>- Double bed or two single beds with premium spring mattresses for optimal support</p><p>- Low-E soundproof glass, UV-resistant (alpha, beta, gamma rays)</p><p>- Premium imported sanitary ware by Grohe – a top European brand</p><p>- Top fire safety system in Nha Trang (fireproof elevator, door, curtain, carpet…)</p><p>- Free 2 bottles of water daily, full minibar, high-speed Wifi</p><p>- Complimentary use of infinity pool and gym</p>', 1, '{\"1\":\"img-deluxes\\/1.png\",\"2\":\"img-deluxes\\/2.png\",\"3\":\"img-deluxes\\/3.png\",\"4\":\"img-deluxes\\/10.png\",\"5\":\"img-deluxes\\/9.png\",\"6\":\"img-deluxes\\/8.png\",\"7\":\"img-deluxes\\/7.png\",\"8\":\"img-deluxes\\/6.png\",\"9\":\"img-deluxes\\/5.png\",\"10\":\"img-deluxes\\/4.png\"}', '0', NULL, 1, 2, 39, 4, 3, 7, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:08:15', 0),
(4, 'Deluxe Twin Room With Ocean View', 'From the spacious balcony of the Deluxe Twin Room With Ocean View room, guests can experience the mystical beauty of the sea, hear the gentle lapping of the waves, and breathe in the fresh air of Nha Trang Bay.', '<p>Deluxe Twin Room With Ocean View&nbsp;– The perfect choice for those seeking privacy and immersive natural beauty</p><p>From the spacious private balcony, guests can admire a panoramic view of Nha Trang Bay where the morning sun glistens across the sea and the salty ocean breeze brings refreshing energy. A peaceful and enchanting setting—designed for premium seaside retreats.</p><p>Highlights:</p><ul><li>37m² with private sea-view balcony, full of natural light</li><li>Two single beds with premium spring mattresses</li><li>Low-E soundproof glass, UV protection (alpha, beta, gamma rays)</li><li>Premium imported sanitary ware from Grohe (Europe)</li><li>Top-tier fire safety system in Nha Trang</li><li>Complimentary: 2 bottles of water/day, minibar, high-speed Wifi</li><li>Free access to infinity pool &amp; gym</li></ul>', 1, '{\"1\":\"img-deluxev\\/1.png\",\"2\":\"img-deluxev\\/8.png\",\"3\":\"img-deluxev\\/7.png\",\"4\":\"img-deluxev\\/6.png\",\"5\":\"img-deluxev\\/5.png\",\"6\":\"img-deluxev\\/4.png\",\"7\":\"img-deluxev\\/3.png\",\"8\":\"img-deluxev\\/2.png\"}', '0', NULL, 9, 2, 39, 5, 3, 7, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:11:06', 0),
(5, 'Pacific Double Room With Ocean View And Private Balcony Bathtub', 'With two spacious balconies facing the vast ocean and Co Tien Mountain, Pacific Double Room With Ocean View And Private Balcony Bathtub offers a unique view and an exclusive outdoor bathtub. Perfect for soaking, sunset-watching, and creating unforgettable moments in a luxurious, poetic atmosphere.', '<p>Pacific Double Room With Ocean View And Private Balcony Bathtub&nbsp;– Two balconies, outdoor bathtub &amp; a romantic escape exclusive to Boton Blue</p><p>With two spacious balconies facing the vast ocean and Co Tien Mountain, Pacific Double offers a unique view and an exclusive outdoor bathtub. Perfect for soaking, sunset-watching, and creating unforgettable moments in a luxurious, poetic atmosphere.</p><p>Highlights:</p><ul><li>44m², modern design with luxurious walnut furnishings</li><li>2 private balconies with direct sea and mountain view</li><li>King-size bed with premium spring mattress</li><li>Outdoor bathtub – exclusive Boton Blue design</li><li>Low-E soundproof glass with UV protection (alpha, beta, gamma)</li><li>Premium imported sanitary ware from Grohe (Europe)</li><li>Top fire safety system in Nha Trang</li><li>Complimentary welcome fruit, 2 bottles of water/day, minibar, high-speed Wifi</li><li>Free access to infinity pool, gym &amp; sauna</li><li>Ideal for honeymoons, anniversaries, or romantic getaways</li></ul>', 0, '{\"1\":\"rooms\\/pacificnct\\/1.png\",\"2\":\"rooms\\/pacificnct\\/8.png\",\"3\":\"rooms\\/pacificnct\\/7.png\",\"4\":\"rooms\\/pacificnct\\/6.png\",\"5\":\"rooms\\/pacificnct\\/5.png\",\"6\":\"rooms\\/pacificnct\\/4.png\",\"7\":\"rooms\\/pacificnct\\/3.png\",\"8\":\"rooms\\/pacificnct\\/2.png\"}', '0', NULL, 5, 1, 44, 2, 1, 6, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:25:32', 0),
(6, 'Pacific Triple Room With Ocean View And Bathtub', 'With dual balconies offering direct views of the sea and cityscape, Pacific Triple provides a rare experience: brilliant sunrise, gentle waves, and sparkling Nha Trang at night—a perfect blend of nature and urban charm.', '<p>Pacific Triple Room With Ocean View And Bathtub&nbsp;– Two balconies facing the sea and city, an ideal space for families and friends</p><p>With dual balconies offering direct views of the sea and cityscape, Pacific Triple provides a rare experience: brilliant sunrise, gentle waves, and sparkling Nha Trang at night—a perfect blend of nature and urban charm.</p><p>Highlights:</p><ul><li>56m², modern design, luxurious walnut wood interior</li><li>2 private balconies with sea and city views</li><li>1 double bed + 1 single bed – ideal for 3–4 guests or families</li><li>Panoramic view of Hon Chong and the city skyline</li><li>Low-E soundproof glass with UV protection</li><li>Premium Grohe bathroom fixtures (Europe)</li><li>One of the safest fire protection systems in Nha Trang</li><li>Free: welcome fruit, 2 bottles of water/day, minibar, high-speed Wifi</li><li>Complimentary infinity pool, gym &amp; daily sauna access</li></ul>', 0, '{\"1\":\"rooms\\/pacificvtp\\/1.png\",\"2\":\"rooms\\/pacificvtp\\/10.png\",\"3\":\"rooms\\/pacificvtp\\/9.png\",\"4\":\"rooms\\/pacificvtp\\/8.png\",\"5\":\"rooms\\/pacificvtp\\/7.png\",\"6\":\"rooms\\/pacificvtp\\/6.png\",\"7\":\"rooms\\/pacificvtp\\/5.png\",\"8\":\"rooms\\/pacificvtp\\/4.png\",\"9\":\"rooms\\/pacificvtp\\/3.png\",\"10\":\"rooms\\/pacificvtp\\/2.png\"}', '0', NULL, 5, 1, 56, 3, 1, 6, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:27:29', 0),
(7, 'Suite Room With Exclusive Ocean View', 'Spanning 80m² with two balconies facing the sea, the Suite offers a refined, private living space. Available in Eastern and Western styles, it combines sophistication with cultural elegance for a premium experience.', '<p>Suite Room With Exclusive Ocean View&nbsp;– A luxurious retreat for elite travelers</p><p>Spanning 80m² with two balconies facing the sea, the Suite offers a refined, private living space. Available in Eastern and Western styles, it combines sophistication with cultural elegance for a premium experience.</p><p>Highlights:</p><ul><li>80m², modern design, premium walnut furnishings</li><li>Two balconies with sea or city views</li><li>King-size bed with Hanvico spring mattress</li><li>Separate living area for maximum comfort</li><li>Low-E soundproof glass, UV protection (alpha, beta, gamma)</li><li>Premium imported Grohe bathroom fixtures (Europe)</li><li>One of Nha Trang’s safest fire safety systems</li><li>Free: welcome fruit, red wine, 2 bottles of water/day, minibar, Wifi</li><li>Free access to infinity pool, gym &amp; sauna</li></ul>', 1, '{\"1\":\"rooms\\/suite\\/6e3214fb-7a23-42c5-a55f-e93400776184.jpg\",\"2\":\"rooms\\/suite\\/edf22bfd-bf96-4492-a247-34e48359b539.jpg\",\"3\":\"rooms\\/suite\\/ffbf8a3b-c86d-40f2-8d22-5a117da54699.jpg\",\"4\":\"rooms\\/suite\\/c0ccd33a-c463-413b-9115-6f9b07c47825.jpg\",\"5\":\"rooms\\/suite\\/bc9e617c-5932-4039-813f-a1c8cbcf344e.jpg\",\"6\":\"rooms\\/suite\\/ac5c0d03-0c6b-483d-a747-47fc1504b4bb.jpg\",\"7\":\"rooms\\/suite\\/b8aa68c3-814a-4cb3-ae98-5645f0fd8f11.jpg\",\"8\":\"rooms\\/suite\\/96478a2b-2f84-4057-a2d7-a631745e0641.jpg\",\"9\":\"rooms\\/suite\\/76adec32-4eec-4163-bd28-f450ccef02da.jpg\",\"10\":\"rooms\\/suite\\/0624bb3c-65aa-4428-b535-d167aa81c328.jpg\",\"11\":\"rooms\\/suite\\/36fe8da9-c91a-454e-8d71-107f3738f1f7.jpg\",\"12\":\"rooms\\/suite\\/8dfb7805-d783-4983-89e4-cd15db4eea8f.jpg\",\"13\":\"rooms\\/suite\\/25d7fa0a-a2c3-4027-8ad0-6f52ddf18d38.jpg\",\"14\":\"rooms\\/suite\\/7eb65c48-b1c9-488e-ae1e-34296fb3a3be.jpg\",\"15\":\"rooms\\/suite\\/6cc46e57-c63e-4ff0-86f3-6b97d1f8ea19.jpg\",\"16\":\"rooms\\/suite\\/5b6fae93-0de5-4569-a442-cf28ee9786ea.jpg\",\"17\":\"rooms\\/suite\\/02f7c2b1-f1cb-4dc4-8a5c-778e3d41ecb9.jpg\",\"18\":\"rooms\\/suite\\/2d7229a2-7b9a-47ed-aeed-87db56388a36.jpg\"}', '0', NULL, 1, 2, 80, 4, 2, 8, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 19:34:16', 0),
(8, 'Presidential Suite', 'Located on the 26th floor—the highest in the hotel—the Presidential Suite boasts 310m² of living space and 360-degree views of Nha Trang Bay, the city, and Co Tien Mountain. Designed for world leaders, elites, and those seeking absolute exclusivity.', '<p>Presidential Suite – The pinnacle of luxury and elite living</p><p>Located on the 26th floor—the highest in the hotel—the Presidential Suite boasts 310m² of living space and 360-degree views of Nha Trang Bay, the city, and Co Tien Mountain. Designed for world leaders, elites, and those seeking absolute exclusivity.</p><p>Highlights:</p><ul><li>310m² on the top floor, full 360° view: sea – mountains – city</li><li>Expansive living area, private dining room, separate work &amp; lounge spaces</li><li>Oversized balcony overlooking the bay and mountains</li><li>King-size bed with premium spring mattress</li><li>Low-E soundproof glass, UV protection (alpha, beta, gamma)</li><li>Premium Grohe bathroom fixtures (Europe)</li><li>Safest fire protection system in Nha Trang</li><li>Complimentary: welcome fruit, wine, daily water, minibar, high-speed Wifi</li><li>Free access to infinity pool, gym, and sauna</li></ul>', 1, '{\"1\":\"rooms\\/phong-tong-thong\\/640d6c11-a40a-4393-9ca1-994af77734db.jpg\",\"2\":\"rooms\\/phong-tong-thong\\/f7a875ba-e09d-496f-a0f7-faa91a363b31.jpg\",\"3\":\"rooms\\/phong-tong-thong\\/ee1c8f98-6615-44b6-b103-216f1fee9356.jpg\",\"4\":\"rooms\\/phong-tong-thong\\/df3fac3c-6356-4f88-80ca-65dbab82ace7.jpg\",\"5\":\"rooms\\/phong-tong-thong\\/e1121848-d163-44a4-abc6-fc8e62cbd488.jpg\",\"6\":\"rooms\\/phong-tong-thong\\/c0acfc09-6bd0-487e-aa2d-19cbd344a91d.jpg\",\"7\":\"rooms\\/phong-tong-thong\\/bcf0edaf-bf9a-49ca-8ff6-40ee8167f9a7.jpg\",\"8\":\"rooms\\/phong-tong-thong\\/42218fbf-0234-42e5-9c42-95ae5b9b886c.jpg\",\"9\":\"rooms\\/phong-tong-thong\\/0484365b-12a3-457c-a56d-c69de129513c.jpg\",\"10\":\"rooms\\/phong-tong-thong\\/888d11af-ee4c-4a98-9bd0-03085b926c6f.jpg\",\"11\":\"rooms\\/phong-tong-thong\\/7903b102-7ccc-4c2a-b0e7-8633b2920ad7.jpg\",\"12\":\"rooms\\/phong-tong-thong\\/46d63b26-40c6-4fd6-9f8b-4021781e2c53.jpg\",\"13\":\"rooms\\/phong-tong-thong\\/0b79b24c-1a8b-4fad-991e-65c5ee1f9eef.jpg\",\"14\":\"rooms\\/phong-tong-thong\\/023bc5f2-5532-45cf-bf3e-231beea0bd0b.jpg\"}', '0', NULL, 9, 2, 310, 6, 1, 9, 2, 'published', '2025-06-10 10:38:06', '2026-03-15 20:36:04', 0);

