INSERT INTO `ht_room_reviews` (`id`, `customer_id`, `room_id`, `star`, `content`, `status`, `created_at`, `updated_at`) VALUES
(1, 9, 7, 5, 'I couldn’t have asked for a better place to stay. The room’s design was elegant, and the comfort level was off the charts. Staying here added a layer of luxury to my trip.', 'approved', '2025-06-10 10:38:25', '2025-06-10 10:38:25'),
(2, 9, 1, 5, 'Top-notch accommodations! The room was well-appointed and had all the necessary amenities. The staff was incredibly friendly and made my stay even more enjoyable.', 'approved', '2025-06-10 10:38:25', '2025-06-10 10:38:25'),
(3, 10, 3, 4, 'I was thoroughly impressed with the attention to detail in the room. Everything from the cozy bed to the modern bathroom exceeded my expectations. Highly recommend!', 'approved', '2025-06-10 10:38:25', '2025-06-10 10:38:25'),
(4, 5, 1, 4, 'I was thoroughly impressed with the attention to detail in the room. Everything from the cozy bed to the modern bathroom exceeded my expectations. Highly recommend!', 'approved', '2025-06-10 10:38:25', '2025-06-10 10:38:25'),
