(5, 'About Us', '[about-us title=&quot;Most Safe &amp; Rated Hotel In London.&quot; subtitle=&quot;About Us&quot; description=&quot;At About Us, we take pride in offering the most secure and top-rated hotels in London. Your safety and comfort are our priorities, which is why our meticulous selection process ensures each hotel meets stringent quality standards. Whether you&rsquo;re visiting for business or leisure, trust us to provide you with a stay that combines the utmost security and exceptional service.&lt;br&gt; &lt;br&gt;Experience London like never before with our curated list of accommodations that boast prime locations and unmatched safety measures. From charming boutique hotels to Luxuryous city-center options, we&rsquo;ve done the groundwork to present you with a variety of choices that guarantee a worry-free stay. Choose About Us for a memorable trip enriched with both the allure of London.&quot; highlights=&quot;Discover the epitome of safe haven in our top-rated London hotels.; Immerse yourself in the heart of London&rsquo;s charm.; Experience the perfect blend of luxury and comfort.&quot; style=&quot;style-2&quot; button_label=&quot;DISCOVER MORE&quot; button_url=&quot;/about-us&quot; signature_image=&quot;general/signature.png&quot; signature_author=&quot;Vincent Smith&quot; top_left_image=&quot;services/about-img-02.png&quot; bottom_right_image=&quot;services/about-img-03.png&quot; floating_right_image=&quot;backgrounds/an-img-02.png&quot;][/about-us][why-choose-us title=\"We Offer Wide Selection of Hotel\" subtitle=\"Rio We Use\" description=\"Explore a variety of handpicked hotels with Rio We Use. Your ideal stay is just a click away. Book now for an unforgettable experience.\" right_image=\"services/skills-img.png\" background_color=\"#291D16\" background_image=\"backgrounds/an-img-05.png\" quantity=\"3\" title_1=\"Quality Production\" percentage_1=\"80\" title_2=\"Maintenance Services\" percentage_2=\"90\" title_3=\"Product Management\" percenta