(11, 'Contact Us', '[contact-form title=&quot;Get In Touch&quot; title_button=&quot;SUBMIT NOW&quot; address_icon=&quot;far fa-map&quot; address_label=&quot;Office Address&quot; address_detail=&quot;380 St Kilda Road, Melbourne &lt;br&gt;VIC 3004, Australia&quot; email_icon=&quot;far fa-envelope-open&quot; email_label=&quot;Message Us&quot; email_detail=&quot;support@example.com &lt;br&gt;info@example.com&quot; work_time_icon=&quot;far fa-clock&quot; work_time_label=&quot;Working Hours&quot; work_time_detail=&quot;Monday to Friday 09:00 to 18:30 &lt;br&gt;Saturday 15:30&quot; phone_icon=&quot;fa fa-phone&quot; phone_label=&quot;(+1) 123 456 78&quot; phone_detail=&quot; 24/7 Customer Service And Returns Support.&quot;][/contact-form][newsletter title=\"Get Best Offers On The Hotel\" subtitle=\"Newsletter\" description=\"With the subscription, enjoy your favourite Hotels without having to think about it\" background_color=\"#F7F5F1\" left_floating_image=\"backgrounds/an-img-07.png\"][/newsletter]', 1, NULL, 'full-width', NULL, 'published', '2025-06-10 10:38:14', '2025-06-10 10:38:14'),
(12, 'Privacy', '<div class=\"about-area5 about-p p-relative\">\n    <div class=\"container pt-60 pb-90\">\n        <div class=\"service-detail\">\n            <div class=\"content-box\">\n                <h2> Privacy Statement </h2>\n                <p>First things first – your privacy is important to us. That might be the kind of thing all these notices say, but we mean it. You place your trust in us by using us services and we value that trust. That means we’re committed to protecting and safeguarding your personal data. We act in our customers’ best interest and we are transparent about the processing of your personal data.</p>\n                <p>If you’ve used us before, you know that us services offers online travel-related services through our own websites and mobile apps, as well as other online platforms such as partners’ websites and social media. We’d like to point out that all the information you are about to read, generally applies to not one, not two, but all of these platforms.</p>\n                <p>If you’ve used us before, you know that us services offers online travel-related services through our own websites and mobile apps, as well as other online platforms such as partners’ websites and social media. We’d like to point out that all the information you are about to read, generally applies to not one, not two, but all of these platforms.</p>\n\n                <h2>Terms we use in this Privacy Statement</h2>\n                <p>\'Trip\' means the various different travel products and services that can be ordered, acquired, purchased, bought, paid, rented, provided, reserved, combined, or consummated by you from the Trip Provider.</p>\n                <p>\'Trip Provider\' means the provider of accommodation (e.g. hotel, motel, apartment, bed & breakfast, landlord), attractions (e.g. (theme) parks, museums, sightseeing tours), transportation provider (e.g. car rentals, cruises, rail, airport rides, coach tours, transfers), tour operators, travel insurances and any other travel or related product or service as from time to time available for Trip Reservation on the platform.</p>\n            </div>\n        </div>\n    </div>\n</div>\n', 1, NULL, 'full-width', NULL, 'published', '2025-06-10 10:38:14', '2025-06-10 10:38:14'),
(13, 'Term and Conditions', '<div class=\"about-area5 about-p p-relative\">\n    <div class=\"container pt-60 pb-90\">\n        <div class=\"service-detail\">\n            <div class=\"content-box\">\n                <h3>Definitions</h3>\n                <p>Some of the words you’ll see have very specific meanings, so please check out the ‘RioRelax dictionary’ at the end of these Terms.</p>\n\n                <h3>About these terms</h3>\n                <p>When you complete your Booking, you accept these Terms and any other terms that you’re provided with during the booking process.</p>\n                <p>The English version of these Terms is the original. If there’s any dispute about the Terms, or any mismatch between the Terms in English and in another language, the Terms as they appear in English will apply. (You can change the language at the top of this page.</p>\n\n                <h3>Our Platform</h3>\n                <p> We take reasonable care in providing our Platform, but we can’t guarantee that everything on it is accurate (we get information from the Service Providers). To the extent permitted by law, we can’t be held responsible for any errors, any interruptions, or any missing bits of information - although we will do everything we can to correct/fix them as soon as we can.</p>\n                <P>We will show you the offers that are available to you, in (what we think is) the right language for you. You can change to another language whenever you like.</P>\n\n                <h3>Prices</h3>\n                <p> When you make a Booking, you agree to pay the cost of the Travel Experience, including any charges and taxes that may apply.</p>\n                <p> Some of the prices you see may have been rounded to the nearest whole number. The price you pay will be based on the original, \'non-rounded\' price (although the actual difference will be tiny anyway).</p>\n            </div>\n        </div>\n    </div>\n</div>\n', 1, NULL, 'full-width', NULL, 'published', '2025-06-10 10:38:14', '2025-06-10 10:38:14'),
(14, 'Boton Blue Dining &amp; Lounge', '[services data-vb-id=\"shortcode_1773474671_0\" title=\"Asian Restaurant\" subtitle=\"Opening hour: daily 10:00 - 22:00\" description=\"Located on the 8th floor of the Boton Blue Hotel & Spa with a panoramic view of the infinity pool and the vast ocean, Asian restaurant gives you exciting moments to enjoy authentic Asian cuisine by friends and relatives.\" left_image=\"dinning/1.png\" button_label=\"View Details\" button_url=\"/asian-restaurant\"][/services]\n\n[feature-area data-vb-id=\"shortcode_1773474671_1\" title=\"Blue Ocean Bar\" subtitle=\"Daily 8:00 AM – 9:00 PM\" description=\"Off the main pool, it is al fresco environment encourages lingering over classic summertime tastes in the Nha Trang sunshine. Order up tropical drinks and sip on refreshing specialty cocktails while you enjoy great conversation and beach-style tunes.\" image=\"dinning/blue-ocean-bar/3.png\" button_primary_label=\"View Details\" button_primary_url=\"/blue-ocean-bar\"][/feature-area]\n\n[feature-area data-vb-id=\"shortcode_1773474671_2\" id=\"shortcode_1773397233_2\" title=\"Sunflower Restaurant\" subtitle=\"Daily 6:30 AM - 10:00 AM\" description=\"Directly overlooking the beautiful ocean, Sunflower Restaurant is the perfect place to start the day with a scrumptious breakfast. A daily breakfast buffet serves the Western and Asian cuisine that suite every taste. The restaurant also serves an innovative a la carte menu for lunch and dinner, buffet for the...\" image=\"dinning/sunflower-restaurant/1.png\" button_primary_label=\"View Details\" button_primary_url=\"/sunflower-restaurant\"][/feature-area]\n\n[feature-area data-vb-id=\"shortcode_1773474671_3\" id=\"shortcode_1773397233_3\" title=\"Guangdong Restaurant\" subtitle=\"Monday - Sunday: 16:30 - 22:00\" description=\"Enjoy fine Chinese cuisine at Guangdong Restaurant while soaking in the breathtaking view of the bay. With its interior adorned with black-red background décor and traditional lanterns, Guangdong Restaurant creates an immersive atmosphere complementing our elegant cuisine.\" image=\"dinning/guangdong-restaurant/959x642.png\" button_primary_label=\"View Details\" button_primary_url=\"guangdong-restaurant\"][/feature-area]', 1, NULL, 'full-width', 'Enjoy the finest dining in town', 'published', '2026-03-13 02:25:49', '2026-03-14 00:51:11'),
(15, 'Guangdong Restaurant', '<link href=\"https://fonts.googleapis.com/css2?family=Antonio:wght@100;200;300;400;500&amp;display=swap\" rel=\"stylesheet\"><div class=\"guangdong-bar\"><figure class=\"table\" style=\"width:100%;\"><table><tbody><tr><td style=\"text-align:left;\"><div class=\"gd-title\">OPENING HOURS</div><div class=\"gd-sub\">MONDAY - SUNDAY: 16:30 - 22:00</div></td><td style=\"text-align:right;\"><div class=\"gd-title\">HOTLINE</div><div class=\"gd-phone\"><span class=\"gd-icon\">☎</span> 0258 383 6868</div></td></tr></tbody></table></figure></div><div class=\"gd-slider\"><div class=\"gd-slides\"><div class=\"gd-slide slide1 active\">&nbsp;</div><div class=\"gd-slide slide2\">&nbsp;</div></div></div><div class=\"gd-restaurant-title\"><span>GUANGDONG RESTAURANT</span></div><section class=\"gd-menu-section\"><div class=\"gd-menu-inner\"><div class=\"gd-menu-slider\"><p><button class=\"gd-prev\">❮</button></p><div class=\"gd-menu-track\"><img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/1.jpg\" alt=\"1.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/2.jpg\" alt=\"2.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/3.jpg\" alt=\"3.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/4.jpg\" alt=\"4.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/5.jpg\" alt=\"5.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/6.jpg\" alt=\"6.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/7.jpg\" alt=\"7.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/8.jpg\" alt=\"8.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/guangdong-restaurant/menu/9.jpg\" alt=\"9.jpg\"> <img src=\"https://botonbluehotel.vt360.vn/storage/dinning/gua