(5, 'Botble\\Page\\Models\\Page', 15, 1, 'template', 'default', 'full-width', '2026-03-15 19:51:39', '2026-03-15 19:51:39'),
(6, 'Botble\\Blog\\Models\\Post', 1, 1, 'name', 'Each of our 8 double rooms has its own distinct.', 'BOTON BLUE HOTEL &amp; SPA YEAR-END PARTY', '2026-03-16 03:05:37', '2026-03-16 03:05:37'),
(7, 'Botble\\Blog\\Models\\Post', 1, 1, 'description', 'Discover a world of unique comfort in our collection of 8 double rooms, each boasting its own distinct charm and character. Immerse yourself in a stay that caters to your individual preferences', 'On the evening of February 4, the entire Boton Blue Hotel &amp; Spa family came together for a warm and memorable year-end celebration held at the Lotus Lobby on the 3rd floor of the hotel, with the presence of the Management Board and all team members.', '2026-03-16 03:05:37', '2026-03-16 03:05:37'),
(8, 'Botble\\Blog\\Models\\Post', 1, 1, 'image', 'news/1.jpg', 'news/spa-year-end-party/z7503628521898-8a8c6d62260735120ea8184e519ad432.jpeg', '2026-03-16 03:05:37', '2026-03-16 03:05:37'),
(9, 'Botble\\Blog\\Models\\Post', 1, 1, 'is_featured', '1', '0', '2026-03-16 03:09:13', '2026-03-16 03:09:13'),
(10, 'Botble\\Blog\\Models\\Post', 2, 1, 'name', 'Essential Qualities of Highly Successful Music', 'CHRISTMAS HARMONY NIGHT 2025', '2026-03-16 21:10:55', '2026-03-16 21:10:55'),
(11, 'Botble\\Blog\\Models\\Post', 2, 1, 'description', 'Delve into the secrets behind the music that resonates deeply with audiences worldwide. Uncover the essential qualities that elevate music from ordinary to extraordinary, as we explore.', 'Let us look back on the unforgettable moments of CHRISTMAS HARMONY NIGHT 2025 at Boton Blue Hotel &amp; Spa — an evening where sparkling lights, elegant melodies, and a warm festive atmosphere came together to create a truly enchanting Christmas celebration.', '2026-03-16 21:10:55', '2026-03-16 21:10:55'),
(12, 'Botble\\Blog\\Models\\Post', 2, 1, 'image', 'news/2.jpg', 'news/christmas-harmony-night-2025/603902553-1510325271099573-6993433745241344189-n.jpeg', '2026-03-16 21:10:55', '2026-03-16 21:10:55'),
(13, 'Botble\\Blog\\Models\\Post', 3, 1, 'name', '9 Things I Love About Shaving My Head', 'OFFICIAL ANNOUNCEMENT FROM BOTON BLUE HOTEL &amp; SPA', '2026-03-16 21:13:02', '2026-03-16 21:13:02'),
(14, 'Botble\\Blog\\Models\\Post', 3, 1, 'description', 'Embark on a personal journey of self-discovery and empowerment as we delve into the unique experience of embracing a bald look. From newfound confidence to a simplified routine, explore the 9 things', 'Driven by our aspiration to elevate guest experiences and proudly represent a Vietnamese luxury hotel brand on the global stage, Boton Blue Hotel &amp; Spa is delighted to announce:', '2026-03-16 21:13:02', '2026-03-16 21:13:02'),
(15, 'Botble\\Blog\\Models\\Post', 3, 1, 'is_featured', '1', '0', '2026-03-16 21:13:02', '2026-03-16 21:13:02'),
(16, 'Botble\\Blog\\Models\\Post', 3, 1, 'image', 'news/3.jpg', 'news/official-announcement/z7143800919525-2687d38dcd5d9603a273490d79d7b01e.jpeg', '2026-03-16 21:13:02', '2026-03-16 21:13:02'),
(17, 'Botble\\Blog\\Models\\Post', 4, 1, 'name', 'Why Teamwork Really Makes The Dream Work', 'THE GRAND TUNA BUFFET PARTY', '2026-03-16 21:24:17', '2026-03-16 21:24:17'),
(18, 'Botble\\Blog\\Models\\Post', 4, 1, 'description', 'Unlock the power of collaboration and synergy in achieving your goals. In this exploration of the importance of teamwork, we delve into real-world examples and insights and how combining diverse skills.', 'On the evening of September 1st, the Oceanic Tuna Buffet Party took place in a luxurious and cozy setting at the Asian Restaurant, 8th floor of Boton Blue Hotel &amp; Spa.', '2026-03-16 21:24:17', '2026-03-16 21:24:17'),
(19, 'Botble\\Blog\\Models\\Post', 4, 1, 'is_featured', '1', '0', '2026-03-16 21:24:17', '2026-03-16 21:24:17'),
(20, 'Botble\\Blog\\Models\\Post', 4, 1, 'image', 'news/4.jpg', 'news/the-grand-tuna-buffet-party/img-4329.jpeg', '2026-03-16 21:24:17', '2026-03-16 21:24:17'),
(21, 'Botble\\Blog\\Models\\Post', 5, 1, 'name', 'The World Caters to Average People', '20th Reunion of Class 43 – Nha Trang University at Boton Blue Hotel &amp; Spa', '2026-03-16 23:42:25', '2026-03-16 23:42:25'),
(22, 'Botble\\Blog\\Models\\Post', 5, 1, 'description', 'Unveil the hidden truths behind success in a world that often values conformity. In a thought-provoking analysis, we examine why societal norms tend to cater to the average and breaking boundaries.', 'This past Saturday, Boton Blue Hotel &amp; Spa had the great honor of hosting the 20-year class reunion for Class 43 – Faculty of Aquaculture and Environment, Nha Trang University (Cohort 2001–2005) at the Lotus Ballroom – 3rd Floor.', '2026-03-16 23:42:25', '2026-03-16 23:42:25'),
(23, 'Botble\\Blog\\Models\\Post', 5, 1, 'image', 'news/5.jpg', 'news/20th-reunion-of-class-43/gen-h-z6871141271576-b04676a18e5beb64a3a142e2b6f82fa2.jpeg', '2026-03-16 23:42:25', '2026-03-16 23:42:25'),
(24, 'Botble\\Blog\\Models\\Post', 6, 1, 'name', 'The litigants on the screen are not actors', 'BOTON BLUE HOTEL &amp; SPA – A PREMIER DESTINATION FOR WORLD-CLASS CULINARY EVENTS &amp; BUSINESS CONNECTIONS', '2026-03-17 00:41:40', '2026-03-17 00:41:40'),
(25, 'Botble\\Blog\\Models\\Post', 6, 1, 'description', 'Take a behind-the-scenes look at the reality of courtroom dramas. Contrary to common assumptions, the litigants you see on the screen are not mere actors, but real people with compelling stories.', 'Recently, the Asian Restaurant (8th floor, Boton Blue Hotel &amp; Spa) had the honor of being selected as the venue for FOOD DISCOVERY DAY – a large-scale culinary event jointly organized by Moonmilk Nha Trang and Kewpie Vietnam. The event brought together leading names in the food, beverage, and distribution industries, with a mission to connect – experience – and spread value to the community.', '2026-03-17 00:41:40', '2026-03-17 00:41:40'),
(26, 'Botble\\Blog\\Models\\Post', 6, 1, 'is_featured', '1', '0', '2026-03-17 00:41:40', '2026-03-17 00:41:40'),
(27, 'Botble\\Blog\\Models\\Post', 6, 1, 'image', 'news/6.jpg', 'news/a-premier-destination-for-world/img-4097.jpeg', '2026-03-17 00:41:40', '2026-03-17 00:41:40'),
(28, 'Botble\\Blog\\Models\\Post', 12, 1, 'name', 'c AT BOTON BLUE HOTEL &amp; SPA 2024 🎄✨', 'CHRISTMAS EVE BUFFET AT BOTON BLUE HOTEL &amp; SPA 2024 🎄✨', '2026-03-17 02:06:51', '2026-03-17 02:06:51');

