(100, 'custom_body_js', '<script>\r\ndocument.addEventListener(\"DOMContentLoaded\", function(){\r\n\r\n/* ========= HERO SLIDER ========= */\r\n\r\nconst gdSlides = document.querySelectorAll(\".gd-slide\")\r\n\r\nif(gdSlides.length){\r\n\r\nlet gdIndex = 0\r\n\r\nfunction gdShowSlide(){\r\n\r\ngdSlides.forEach(function(s){\r\ns.classList.remove(\"active\")\r\n})\r\n\r\ngdSlides[gdIndex].classList.add(\"active\")\r\n\r\ngdIndex++\r\n\r\nif(gdIndex >= gdSlides.length){\r\ngdIndex = 0\r\n}\r\n\r\n}\r\n\r\nsetInterval(gdShowSlide,4000)\r\n\r\n}\r\n\r\n\r\n/* ========= MENU SLIDER ========= */\r\n\r\nconst slider = document.querySelector(\'.gd-menu-track\')\r\nconst slides = document.querySelectorAll(\'.gd-menu-track img\')\r\nconst prev = document.querySelector(\'.gd-prev\')\r\nconst next = document.querySelector(\'.gd-next\')\r\n\r\nif(slider && slides.length && prev && next){\r\n\r\nlet index = 0\r\n\r\nfunction updateSlider(){\r\nslider.style.transform = \"translateX(-\" + (index * 100) + \"%)\"\r\n}\r\n\r\nnext.addEventListener(\'click\', function(){\r\n\r\nindex++\r\n\r\nif(index >= slides.length){\r\nindex = 0\r\n}\r\n\r\nupdateSlider()\r\n\r\n})\r\n\r\nprev.addEventListener(\'click\', function(){\r\n\r\nindex--\r\n\r\nif(index < 0){\r\nindex = slides.length - 1\r\n}\r\n\r\nupdateSlider()\r\n\r\n})\r\n\r\n}\r\n\r\n})\r\n</script>', NULL, '2026-03-20 17:55:05'),
