INSERT INTO `testimonials` (`id`, `name`, `content`, `image`, `company`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Adam Williams', 'A true gem! Impeccable service, stunning views, and utmost comfort. Our stay was pure perfection. Planning our return!', 'testimonials/01.png', 'CEO Of Microsoft', 'published', '2025-06-10 10:38:15', '2025-06-10 10:38:15'),
(2, 'Retha Deowalim', 'Exceeded expectations in every way. Elegant rooms, delectable dining. Our stay was pure perfection. 5 stars!\"', 'testimonials/02.png', 'CEO Of Apple', 'published', '2025-06-10 10:38:15', '2025-06-10 10:38:15'),
(3, 'Sam J. Wasim', 'Paradise found. Serene ambiance, exceptional amenities, and warm hospitality. Already planning our return!', 'testimonials/03.png', 'Pio Founder', 'published', '2025-06-10 10:38:15', '2025-06-10 10:38:15'),
(4, 'Daniel Rodriguez', 'An exceptional experience from start to finish. The attention to detail, combined with breathtaking surroundings.', 'testimonials/04.png', 'VP Of Google', 'published', '2025-06-10 10:38:15', '2025-06-10 10:38:15'),
(5, 'Daniel Chang', 'A true haven for relaxation. Every aspect of our stay, from the luxurious rooms to the exquisite dining, was exceptional.', 'testimonials/05.png', 'Founder Of SpaceX', 'published', '2025-06-10 10:38:15', '2025-06-10 10:38:15'),
(6, 'Isabella Russo', 'Indulgence at its finest. The blend of modern luxury and natural beauty exceeded our expectations, was exceptional.', 'testimonials/06.png', 'Fashion Designer', 'published', '2025-06-10 10:38:15', '2025-06-10 10:38:15');

